"use server";

import { promises as fs } from "fs";
import { revalidatePath } from "next/cache";
import path from "path";
import type { FileNode } from "./file-browser";

const ROOT_DIR = process.cwd();

async function buildFileTree(dir: string, relativePath = ""): Promise<FileNode[]> {
  const entries = await fs.readdir(dir, { withFileTypes: true });
  const nodes: FileNode[] = [];

  for (const entry of entries) {
    // Skip node_modules and .git directories
    if (entry.name === "node_modules" || entry.name === ".git") {
      continue;
    }

    const currentPath = path.join(relativePath, entry.name);
    const fullPath = path.join(dir, entry.name);

    if (entry.isDirectory()) {
      const children = await buildFileTree(fullPath, currentPath);
      nodes.push({
        name: entry.name,
        path: currentPath,
        type: "directory",
        children,
      });
    } else {
      const stats = await fs.stat(fullPath);
      nodes.push({
        name: entry.name,
        path: currentPath,
        type: "file",
        size: stats.size,
        modifiedAt: stats.mtime.toISOString(),
      });
    }
  }

  return nodes.sort((a, b) => {
    if (a.type === "directory" && b.type === "file") return -1;
    if (a.type === "file" && b.type === "directory") return 1;
    return a.name.localeCompare(b.name);
  });
}

export async function getFileTree() {
  try {
    const tree = await buildFileTree(ROOT_DIR);
    revalidatePath("/browser");
    return { tree };
  } catch (error) {
    return { error: "Failed to load file tree" };
  }
}

export async function getFileStats(filePath: string) {
  try {
    const fullPath = path.join(ROOT_DIR, filePath);
    const stats = await fs.stat(fullPath);

    return {
      stats: {
        size: stats.size,
        modifiedAt: stats.mtime.toISOString(),
        createdAt: stats.birthtime.toISOString(),
        isDirectory: stats.isDirectory(),
      },
    };
  } catch (error) {
    return { error: "Failed to get file stats" };
  }
}

"use client";

import { useRouter } from "next/navigation";
import { useCallback, useEffect, useState } from "react";
import { toast } from "sonner";
import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";
import { getFileStats, getFileTree } from "./actions";
import { FileStats } from "./file-stats";
import { File, Folder, Tree } from "./file-tree";

export interface FileNode {
  name: string;
  path: string;
  type: "file" | "directory";
  children?: FileNode[];
  size?: number;
  modifiedAt?: string;
}

interface TreeElement {
  id: string;
  isSelectable: true;
  name: string;
  path: string;
  children?: TreeElement[];
}

const convertToTreeElements = (nodes: FileNode[], parentPath = ""): TreeElement[] => {
  return nodes.map((node, index) => {
    const currentPath = parentPath ? `${parentPath}/${node.name}` : node.name;
    return {
      id: currentPath,
      isSelectable: true,
      name: node.name,
      path: currentPath,
      ...(node.children && { children: convertToTreeElements(node.children, currentPath) }),
    };
  });
};

const renderTreeNodes = (nodes: FileNode[], onSelect: (node: FileNode) => void) => {
  return nodes.map((node, index) => {
    const key = `${node.path}-${index}`;
    if (node.type === "directory") {
      return (
        <Folder key={key} element={node.name} value={node.path}>
          {node.children && renderTreeNodes(node.children, onSelect)}
        </Folder>
      );
    }
    return (
      <File key={key} value={node.path} onClick={() => onSelect(node)}>
        <p className="truncate w-full">{node.name}</p>
      </File>
    );
  });
};

export function FileBrowser() {
  const router = useRouter();
  const [files, setFiles] = useState<FileNode[]>([]);
  const [selectedFile, setSelectedFile] = useState<FileNode | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedFileStats, setSelectedFileStats] = useState<any>(null);
  const [expandedPaths, setExpandedPaths] = useState<string[]>([]);

  const loadFiles = useCallback(async () => {
    try {
      setLoading(true);
      const result = await getFileTree();

      if (result.error) {
        toast.error(result.error);
        return;
      }

      const tree = result?.tree ?? [];

      setFiles(tree);
      // Initially expand root directories
      const rootPaths = tree.filter((node) => node.type === "directory").map((node) => node.path);
      setExpandedPaths(rootPaths);
      router.refresh();
    } catch (error) {
      toast.error("Failed to load file tree");
    } finally {
      setLoading(false);
    }
  }, [router]);

  const handleFileSelect = async (node: FileNode) => {
    setSelectedFile(node);
    if (node.type === "file") {
      const stats = await getFileStats(node.path);
      if (stats.error) {
        toast.error(stats.error);
        return;
      }
      setSelectedFileStats(stats.stats);
    } else {
      setSelectedFileStats(null);
    }
  };

  useEffect(() => {
    loadFiles();
  }, [loadFiles]);

  if (loading) {
    return (
      <div className="grid grid-cols-[300px_1fr] gap-6">
        <Skeleton className="h-[500px] w-full" />
        <Skeleton className="h-[500px] w-full" />
      </div>
    );
  }

  const treeElements = convertToTreeElements(files);

  return (
    <div className="grid grid-cols-[300px_1fr] gap-6">
      <div className="border rounded-lg p-4">
        <Tree
          className="h-[500px] overflow-auto bg-background p-2"
          initialExpandedItems={expandedPaths}
          elements={treeElements}
        >
          {renderTreeNodes(files, handleFileSelect)}
        </Tree>
      </div>
      <div
        className={cn(
          "border rounded-lg p-6",
          "min-h-[500px]",
          !selectedFile && "flex items-center justify-center text-muted-foreground"
        )}
      >
        {selectedFile ? (
          <FileStats file={selectedFile} extraStats={selectedFileStats} />
        ) : (
          <p>Select a file to view its details</p>
        )}
      </div>
    </div>
  );
}

import { FileIcon, FolderIcon } from "lucide-react";
import type { FileNode } from "./file-browser";

interface FileStatsProps {
  file: FileNode;
  extraStats?: {
    size: number;
    modifiedAt: string;
    createdAt: string;
    isDirectory: boolean;
  };
}

export function FileStats({ file, extraStats }: FileStatsProps) {
  const formatSize = (size?: number) => {
    if (!size) return "N/A";
    const units = ["B", "KB", "MB", "GB"];
    let value = size;
    let unitIndex = 0;

    while (value >= 1024 && unitIndex < units.length - 1) {
      value /= 1024;
      unitIndex++;
    }

    return `${value.toFixed(2)} ${units[unitIndex]}`;
  };

  const formatDate = (date?: string) => {
    if (!date) return "N/A";
    return new Date(date).toLocaleString();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3">
        {file.type === "directory" ? (
          <FolderIcon className="h-8 w-8 text-blue-500" />
        ) : (
          <FileIcon className="h-8 w-8 text-gray-500" />
        )}
        <h2 className="text-2xl font-semibold">{file.name}</h2>
      </div>

      <div className="grid gap-4">
        <div className="grid grid-cols-2 gap-2 p-4 bg-muted rounded-lg">
          <span className="text-muted-foreground">Type</span>
          <span className="font-medium">{file.type}</span>
        </div>

        <div className="grid grid-cols-2 gap-2 p-4 bg-muted rounded-lg">
          <span className="text-muted-foreground">Path</span>
          <span className="font-medium break-all">{file.path}</span>
        </div>

        {file.type === "file" && (
          <>
            <div className="grid grid-cols-2 gap-2 p-4 bg-muted rounded-lg">
              <span className="text-muted-foreground">Size</span>
              <span className="font-medium">{formatSize(extraStats?.size)}</span>
            </div>

            <div className="grid grid-cols-2 gap-2 p-4 bg-muted rounded-lg">
              <span className="text-muted-foreground">Created</span>
              <span className="font-medium">{formatDate(extraStats?.createdAt)}</span>
            </div>

            <div className="grid grid-cols-2 gap-2 p-4 bg-muted rounded-lg">
              <span className="text-muted-foreground">Last Modified</span>
              <span className="font-medium">{formatDate(extraStats?.modifiedAt)}</span>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

"use client";

import * as AccordionPrimitive from "@radix-ui/react-accordion";
import { FileIcon, FolderIcon, FolderOpenIcon } from "lucide-react";
import type { HTMLAttributes, ReactNode } from "react";
import * as React from "react";

import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";

interface TreeViewElement {
  id: string;
  name: string;
  isSelectable?: boolean;
  children?: TreeViewElement[];
}

interface TreeContextProps {
  selectedId: string | undefined;
  expandedItems: string[];
  indicator: boolean;
  handleExpand: (id: string) => void;
  selectItem: (id: string) => void;
  setExpandedItems: React.Dispatch<React.SetStateAction<string[]>>;
  openIcon?: ReactNode;
  closeIcon?: ReactNode;
  direction: "rtl" | "ltr";
}

const TreeContext = React.createContext<TreeContextProps | null>(null);

const useTree = () => {
  const context = React.useContext(TreeContext);
  if (!context) {
    throw new Error("useTree must be used within a TreeProvider");
  }
  return context;
};

interface TreeViewComponentProps extends HTMLAttributes<HTMLDivElement> {}

type Direction = "rtl" | "ltr" | undefined;

type TreeViewProps = {
  initialSelectedId?: string;
  indicator?: boolean;
  elements?: TreeViewElement[];
  initialExpandedItems?: string[];
  openIcon?: ReactNode;
  closeIcon?: ReactNode;
} & TreeViewComponentProps;

interface FolderProps extends AccordionPrimitive.AccordionItemProps {
  element: string;
  isSelectable?: boolean;
  isSelect?: boolean;
}

interface FileProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  value: string;
  handleSelect?: (id: string) => void;
  isSelectable?: boolean;
  isSelect?: boolean;
  fileIcon?: ReactNode;
}

interface CollapseButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  elements: TreeViewElement[];
  expandAll?: boolean;
}

const Tree = React.forwardRef<HTMLDivElement, TreeViewProps>(
  (
    {
      className,
      elements,
      initialSelectedId,
      initialExpandedItems = [],
      children,
      indicator = true,
      openIcon,
      closeIcon,
      dir,
      ...props
    },
    ref
  ) => {
    const [selectedId, setSelectedId] = React.useState<string | undefined>(initialSelectedId);
    const [expandedItems, setExpandedItems] = React.useState<string[]>(initialExpandedItems);

    const selectItem = React.useCallback((id: string) => {
      setSelectedId(id);
    }, []);

    const handleExpand = React.useCallback((id: string) => {
      setExpandedItems((prev: string[]) => {
        const filtered = prev.filter((item) => item !== id);
        return prev.includes(id) ? filtered : [...filtered, id];
      });
    }, []);

    const expandSpecificTargetedElements = React.useCallback(
      (elements?: TreeViewElement[], selectId?: string) => {
        if (!elements || !selectId) return;
        const findParent = (currentElement: TreeViewElement, currentPath: string[] = []) => {
          const isSelectable = currentElement.isSelectable ?? true;
          const newPath = [...currentPath, currentElement.id].filter(
            (id): id is string => id !== undefined
          );
          if (currentElement.id === selectId) {
            if (isSelectable) {
              setExpandedItems((prev: string[]) => [...prev, ...newPath]);
            } else if (newPath.includes(currentElement.id)) {
              const filteredPath = newPath.slice(0, -1);
              setExpandedItems((prev: string[]) => [...prev, ...filteredPath]);
            }
            return;
          }
          if (isSelectable && currentElement.children && currentElement.children.length > 0) {
            for (const child of currentElement.children) {
              findParent(child, newPath);
            }
          }
        };
        for (const element of elements) {
          findParent(element);
        }
      },
      []
    );

    React.useEffect(() => {
      if (initialSelectedId && elements) {
        expandSpecificTargetedElements(elements, initialSelectedId);
      }
    }, [initialSelectedId, elements, expandSpecificTargetedElements]);

    const direction = dir === "rtl" ? "rtl" : "ltr";

    return (
      <TreeContext.Provider
        value={{
          selectedId,
          expandedItems,
          handleExpand,
          selectItem,
          setExpandedItems,
          indicator,
          openIcon,
          closeIcon,
          direction,
        }}
      >
        <div className={cn("size-full", className)}>
          <ScrollArea ref={ref} className="relative h-full px-2" dir={dir as Direction}>
            <AccordionPrimitive.Root
              {...props}
              type="multiple"
              defaultValue={expandedItems}
              value={expandedItems}
              className="flex flex-col gap-1"
              onValueChange={(value: string[]) => {
                const newValue = value[0];
                if (typeof newValue === "string") {
                  setExpandedItems((prev) => Array.from(new Set([...prev, newValue])));
                }
              }}
              dir={dir as Direction}
            >
              {children}
            </AccordionPrimitive.Root>
          </ScrollArea>
        </div>
      </TreeContext.Provider>
    );
  }
);

Tree.displayName = "Tree";

const TreeIndicator = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => {
    const { direction } = useTree();

    return (
      <div
        dir={direction}
        ref={ref}
        className={cn(
          "absolute left-1.5 h-full w-px rounded-md bg-muted py-3 duration-300 ease-in-out hover:bg-slate-300 rtl:right-1.5",
          className
        )}
        {...props}
      />
    );
  }
);

TreeIndicator.displayName = "TreeIndicator";

const Folder = React.forwardRef<HTMLDivElement, FolderProps & React.HTMLAttributes<HTMLDivElement>>(
  ({ className, element, value, isSelectable = true, isSelect, children, ...props }, ref) => {
    const {
      direction,
      handleExpand,
      expandedItems,
      indicator,
      setExpandedItems,
      openIcon,
      closeIcon,
    } = useTree();

    return (
      <AccordionPrimitive.Item {...props} value={value} className="relative h-full overflow-hidden">
        <AccordionPrimitive.Trigger
          className={cn("flex items-center gap-1 rounded-md text-sm", className, {
            "bg-muted rounded-md": isSelect && isSelectable,
            "cursor-pointer": isSelectable,
            "cursor-not-allowed opacity-50": !isSelectable,
          })}
          disabled={!isSelectable}
          onClick={() => handleExpand(value)}
        >
          {expandedItems?.includes(value)
            ? (openIcon ?? <FolderOpenIcon className="size-4" />)
            : (closeIcon ?? <FolderIcon className="size-4" />)}
          <span>{element}</span>
        </AccordionPrimitive.Trigger>
        <AccordionPrimitive.Content className="relative h-full overflow-hidden text-sm data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down">
          {element && indicator && <TreeIndicator aria-hidden="true" />}
          <AccordionPrimitive.Root
            dir={direction}
            type="multiple"
            className="ml-5 flex flex-col gap-1 py-1 rtl:mr-5"
            defaultValue={expandedItems}
            value={expandedItems}
            onValueChange={(value: string[]) => {
              const newValue = value[0];
              if (typeof newValue === "string") {
                setExpandedItems((prev) => Array.from(new Set([...prev, newValue])));
              }
            }}
          >
            {children}
          </AccordionPrimitive.Root>
        </AccordionPrimitive.Content>
      </AccordionPrimitive.Item>
    );
  }
);

Folder.displayName = "Folder";

const File = React.forwardRef<HTMLButtonElement, FileProps>(
  (
    {
      value,
      className,
      handleSelect,
      isSelectable = true,
      isSelect,
      fileIcon,

      children,
      ...props
    },
    ref
  ) => {
    const { direction, selectedId, selectItem } = useTree();
    const isSelected = isSelect ?? selectedId === value;
    return (
      <button
        ref={ref}
        type="button"
        disabled={!isSelectable}
        className={cn(
          "flex w-fit max-w-full items-center gap-1 rounded-md pr-1 text-sm duration-200 ease-in-out rtl:pl-1 rtl:pr-0",
          {
            "bg-muted": isSelected && isSelectable,
          },
          isSelectable ? "cursor-pointer" : "cursor-not-allowed opacity-50",
          direction === "rtl" ? "rtl" : "ltr",
          className
        )}
        onClick={() => selectItem(value)}
        {...props}
      >
        {fileIcon ?? <FileIcon className="size-4" />}
        {children}
      </button>
    );
  }
);

File.displayName = "File";

const CollapseButton = React.forwardRef<HTMLButtonElement, CollapseButtonProps>(
  ({ className, elements, expandAll = false, children, ...props }, ref) => {
    const { expandedItems, setExpandedItems } = useTree();

    const expendAllTree = React.useCallback(
      (elements: TreeViewElement[]) => {
        const expandTree = (element: TreeViewElement) => {
          const isSelectable = element.isSelectable ?? true;
          if (isSelectable && element.children && element.children.length > 0) {
            setExpandedItems((prev: string[]) => [...prev, element.id]);
            for (const child of element.children) {
              expandTree(child);
            }
          }
        };
        for (const element of elements) {
          expandTree(element);
        }
      },
      [setExpandedItems]
    );

    const closeAll = React.useCallback(() => {
      setExpandedItems([]);
    }, [setExpandedItems]);

    React.useEffect(() => {
      if (expandAll) {
        expendAllTree(elements);
      }
    }, [expandAll, elements, expendAllTree]);

    return (
      <Button
        variant={"ghost"}
        className="absolute bottom-1 right-2 h-8 w-fit p-1"
        onClick={
          expandedItems && expandedItems.length > 0 ? closeAll : () => expendAllTree(elements)
        }
        ref={ref}
        {...props}
      >
        {children}
        <span className="sr-only">Toggle</span>
      </Button>
    );
  }
);

CollapseButton.displayName = "CollapseButton";

export { CollapseButton, File, Folder, Tree, type TreeViewElement };

